+                        <small class="text-muted">@col</small>
+                    </div>
+                </div>
+            </div>
+        }
+        <div class="col">
+            <div class="card text-center border-danger">
+                <div class="card-body py-2">
+                    <div class="fw-bold text-danger">@allTasks.Count(t => t.DueDate < DateTime.Today)</div>
+                    <small class="text-muted">Overdue</small>
+                </div>
+            </div>
+        </div>
+    </div>
+
+    <!-- Search Bar -->
+    <div class="mb-3">
+        <input type="text" class="form-control" placeholder="Search tasks by title..."
+               @bind="searchText" @bind:event="oninput" />
+    </div>
+
+    <!-- Kanban Columns -->
+    <div class="row g-3">
+        @for (int i = 0; i < Columns.Length; i++)
+        {
+            var colIndex = i;
+            var colName = Columns[colIndex];
+            var columnTasks = GetFilteredTasksForColumn(colName);
+
+            <div class="col-md-4">
+                <div class="card h-100">
+                    <div class="card-header d-flex justify-content-between align-items-center">
+                        <strong>@colName</strong>
+                        <span class="badge bg-secondary">@columnTasks.Count</span>
+                    </div>
+                    <div class="card-body d-flex flex-column gap-2 p-2" style="min-height: 200px;">
+                        @foreach (var task in columnTasks)
+                        {
+                            <div class="card shadow-sm">
+                                <div class="card-body p-2">
+                                    <div class="fw-semibold mb-1">@task.Title</div>
+                                    <div class="d-flex justify-content-between align-items-center mb-1">
+                                        <small class="text-muted">@task.Assignee</small>
+                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
+                                    </div>
+                                    <div class="d-flex justify-content-between align-items-center">
+                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                        <div>
+                                            @if (colIndex > 0)
+                                            {
+                                                <button class="btn btn-outline-secondary btn-sm me-1"
+                                                        @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex - 1])"
+                                                        disabled="@isBusy">
+                                                    &larr; Move Left
+                                                </button>
+                                            }
+                                            @if (colIndex < Columns.Length - 1)
+                                            {
+                                                <button class="btn btn-outline-secondary btn-sm"
+                                                        @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex + 1])"
+                                                        disabled="@isBusy">
+                                                    Move Right &rarr;
+                                                </button>
+                                            }
+                                        </div>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (addingToColumn == colName)
+                        {
+                            <div class="card border-primary mt-auto">
+                                <div class="card-body p-2">
+                                    <input type="text" class="form-control form-control-sm mb-1"
+                                           placeholder="Title" @bind="newTitle" />
+                                    <input type="text" class="form-control form-control-sm mb-1"
+                                           placeholder="Assignee" @bind="newAssignee" />
+                                    <select class="form-select form-select-sm mb-1" @bind="newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm mb-2"
+                                           @bind="newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-primary btn-sm flex-fill"
