+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer p-2">
+                        <button class="btn btn-outline-primary btn-sm w-100"
+                                @onclick="() => StartAdd(colName)"
+                                disabled="@(addingToColumn is not null)">
+                            + Add Task
+                        </button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
